import React, { useState, useEffect } from 'react';
import { WEDDING } from '../weddingData';
import './Hero.css';

export default function Hero() {
  const [timeLeft, setTimeLeft] = useState(calculateTimeLeft());

  function calculateTimeLeft() {
    const difference = +new Date(WEDDING.date) - +new Date();
    let timeLeft = {};

    if (difference > 0) {
      timeLeft = {
        days: Math.floor(difference / (1000 * 60 * 60 * 24)),
        hours: Math.floor((difference / (1000 * 60 * 60)) % 24),
        minutes: Math.floor((difference / 1000 / 60) % 60),
        seconds: Math.floor((difference / 1000) % 60),
      };
    } else {
      timeLeft = { days: 0, hours: 0, minutes: 0, seconds: 0 };
    }
    return timeLeft;
  }

  useEffect(() => {
    const timer = setInterval(() => {
      setTimeLeft(calculateTimeLeft());
    }, 1000);
    return () => clearInterval(timer);
  }, []);

  return (
    <header id="hero" className="hero-section">
      <div className="hero-overlay" />
      <div className="hero-content">
        <span className="hero-subtitle">We Are Getting Married</span>
        <h1 className="hero-title">{WEDDING.groomName} &amp; {WEDDING.brideName}</h1>

        <div className="countdown-container">
          <div className="countdown-box">
            <span className="countdown-value">{timeLeft.days || 0}</span>
            <span className="countdown-label">Days</span>
          </div>
          <div className="countdown-box">
            <span className="countdown-value">{timeLeft.hours || 0}</span>
            <span className="countdown-label">Hours</span>
          </div>
          <div className="countdown-box">
            <span className="countdown-value">{timeLeft.minutes || 0}</span>
            <span className="countdown-label">Minutes</span>
          </div>
          <div className="countdown-box">
            <span className="countdown-value">{timeLeft.seconds || 0}</span>
            <span className="countdown-label">Seconds</span>
          </div>
        </div>

        <button 
          className="hero-btn"
          onClick={() => document.getElementById('rsvp')?.scrollIntoView({ behavior: 'smooth' })}
        >
          Save the Date
        </button>
      </div>
    </header>
  );
}
